import crypto from 'crypto';
export const shareService = {
  async create(resourceId: string, permission: 'view' | 'comment', expiresAt: Date) {
    const token = crypto.randomBytes(24).toString('base64url');
    await ShareModel.create({ token, resourceId, permission, expiresAt, createdBy: currentUser() });
    return token;
  },
  async resolve(token: string) {
    const s = await ShareModel.findOne({ token });
    if (!s || s.expiresAt < new Date() || s.revoked) throw new NotFoundError();
    return s;
  }
};

